const { resumeProfile, companyName, role, hrName, additionalNotes } = $json.body;

// Greeting Logic
const greeting = hrName ? `Dear ${hrName.trim()},` : 'Dear Hiring Team,';

// CTA Requirement
const cta = "I'd appreciate your feedback even if my profile isn't selected. Your feedback will help me improve future applications.";

// Prepare AI prompt
const prompt = `Write a professional job application email to ${companyName} for the position of ${role}.

Greeting: ${greeting}

Candidate Profile Details:
Primary Role: ${resumeProfile.primaryRole}
Skills: ${resumeProfile.skills.join(', ')}
Experience: ${resumeProfile.experience}
Projects: ${JSON.stringify(resumeProfile.projects)}
Technologies: ${resumeProfile.technologies ? resumeProfile.technologies.join(', ') : ''}

Additional Vacancy Notes:
${additionalNotes || 'None'}

Mandatory Ending CTA:
${cta}

Guidelines:
- Use ONLY real candidate details from the profile. Do not hallucinate or add fake roles/projects.
- Focus on relevant skills and experience matching the ${role} job title.
- Keep it highly professional and concise.
- Return the response strictly as a JSON object with two keys: "subject" and "body". Do not include any other text or markdown wraps.`;

return {
  prompt,
  companyName,
  role,
  greeting,
  cta
};

let parsedEmail;
try {
  const responseText = $json.candidates?.[0]?.content?.parts?.[0]?.text;
  if (!responseText) throw new Error('No candidates text');
  parsedEmail = JSON.parse(responseText);
} catch (e) {
  // Mock Fallback Email Draft
  parsedEmail = {
    subject: `Application for ${$node["Prepare Context"].json.role} - Candidate`,
    body: `${$node["Prepare Context"].json.greeting}

I am writing to express my interest in the ${$node["Prepare Context"].json.role} position at ${$node["Prepare Context"].json.companyName}.

Based on my profile, I bring relevant skills and experience in software development and API orchestration. I have worked on modular platforms and enjoy building clean, robust systems.

${$node["Prepare Context"].json.cta}

Sincerely,
Candidate`
  };
}

return {
  success: true,
  subject: parsedEmail.subject,
  body: parsedEmail.body
};
